1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_OF_3_BASE_PREMIUM = 60;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string };
16	type Step = { op: "quote"; items: Item[] };
17	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
18	type QuoteResult = { premium: number };
19	
20	const withFirstInsurance = (base: number): number =>
21	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
22	
23	const itemPremium = (item: Item): number =>
24	  withFirstInsurance(BASE_PREMIUM[item.type]);
25	
26	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
27	
28	const componentGroupPremium = (type: string, count: number): number =>
29	  count === 3
30	    ? withFirstInsurance(BLOCK_OF_3_BASE_PREMIUM)
31	    : count * withFirstInsurance(BASE_PREMIUM[type]);
32	
33	const countByType = (items: Item[]): Map<string, number> => {
34	  const counts = new Map<string, number>();
35	  for (const item of items) {
36	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	  }
38	  return counts;
39	};
40	
41	const sumComponentPremiums = (components: Item[]): number => {
42	  let total = 0;
43	  for (const [type, count] of countByType(components)) {
44	    total += componentGroupPremium(type, count);
45	  }
46	  return total;
47	};
48	
49	const sumMainItemPremiums = (mainItems: Item[]): number =>
50	  mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
51	
52	const sumItemPremiums = (items: Item[]): number => {
53	  const components = items.filter(isComponent);
54	  const mainItems = items.filter((item) => !isComponent(item));
55	  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
56	};
57	
58	const quoteStep = (step: Step): QuoteResult => ({
59	  premium: Math.ceil(sumItemPremiums(step.items) + PROCESSING_FEE),
60	});
61	
62	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
63	  results: scenario.steps.map(quoteStep),
64	});
65

