16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single plain amulet (newcomer first item) → base 60 + first 6 + fee 5 = 71 G", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("single plain staff (newcomer first item) → base 80 + first 8 + fee 5 = 93 G", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it("single plain potion (newcomer first item) → base 40 + first 4 + fee 5 = 49 G", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // --- Components and "building blocks of 3 alike" ---
45	  it("2 runes → base 50 G (no block); final premium with first-insurance+fee = 60 G", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 60 }] });
51	  });
52	  it("3 runes → base 60 G (block applies); premium 60 + first 6 + fee 5 = 71 G", () => {
53	    const result = runScenario({
54	      customer: { yearsWithMHPCO: 0 },
55	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
56	    });
57	    expect(result).toEqual({ results: [{ premium: 71 }] });
58	  });
59	  it("4 runes → base 100 G (no block); premium = 100 + 10 + 5 = 115 G", () => {
60	    const result = runScenario({
61	      customer: { yearsWithMHPCO: 0 },
62	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
63	    });
64	    expect(result).toEqual({ results: [{ premium: 115 }] });
65	  });
66	  it("7 runes → base 175 G (no block; block requires exactly 3); premium = 175 + 17.5 + 5 = 197.5 → rounds up to 198", () => {
67	    const result = runScenario({
68	      customer: { yearsWithMHPCO: 0 },
69	      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }],
70	    });
71	    expect(result).toEqual({ results: [{ premium: 198 }] });
72	  });
73	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
74	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
75	
76	  // --- Item-specific modifiers (cursed, high enchantment) ---
77	  it.todo("cursed sword adds 50% surcharge on the cursed item's base premium");
78	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
79	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
80	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
81	
82	  // --- Policy-wide modifiers ---
83	  it.todo("loyalty discount applies for customer with exactly 2 years");
84	  it.todo("loyalty discount does NOT apply for customer with 1 year");
85	  it.todo("first insurance surcharge applies per item in a quote");
86	  it.todo("follow-up contract discount (15%) applies to second quote in scenario");
87	
88	  // --- Modifier scope on multi-item policies ---
89	  it.todo("cursed sword + plain amulet → cursed surcharge applies only to cursed item (210 G before further modifiers and fee)");
90	
91	  // --- Rounding ---
92	  it.todo("premium of 197.5 G rounds UP to 198 G (MHPCO's favor)");
93	
94	  // --- Integration examples ---
95	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
96	  it.todo("long-standing customer (3yrs), 2nd quote, cursed sword (steel, ench 7) → premium 160 G; first-insurance still applies to each new sword");
97	
98	  // --- Quote error cases ---
99	  it.todo("quote with unknown item type → CLI exits non-zero, writes to stderr, no results to stdout");
100	
101	  // --- Claim: standard reimbursement ---
102	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
103	  it.todo("damage to a rune (insurance 250 G), damage 200 G → payout 100 G");
104	
105	  // --- Claim: enchantment threshold ---
106	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
107	
108	  // --- Claim: dragon material ---
109	  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
110	
111	  // --- Claim: enchantment threshold vs dragon material ---
112	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");
113	  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench clause applies, then deductible)");
114	
115	  // --- Claim: deductible per damage event ---
116	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per damaged item)");
117	
118	  // --- Claim: multiple items of same type ---
119	  it.todo("two swords insured; dragon attack damages both → each damage entry treated separately with own deductible");
120	  it.todo("claim has more entries of a type than policy covers → CLI exits non-zero (claim rejected)");
121	
122	  // --- Claim: cap exhaustion ---
123	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
124	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; modifiers don't raise cap)");
125	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
126	  it.todo("sword insured; two successive claims of 1500 G → first 1400 G payout cap remaining 600; second 600 G payout cap remaining 0");
127	
128	  // --- Claim: rounding ---
129	  it.todo("payout calculation 350.5 G rounds DOWN to 350 G");
130	
131	  // --- Claim error cases ---
132	  it.todo("claim references item not in policy → CLI exits non-zero, stderr");
133	  it.todo("claim references item with unknown type → CLI exits non-zero, stderr");
134	  it.todo("claim has damage with amount: -200 → CLI exits non-zero, stderr");
135	});
